function setLang(lang) {
  TEKPAIR_LANG = lang;
  localStorage.setItem('tp_lang', lang);
  // Actualizar botón nómina (no usa data-t para evitar mostrar la clave)
  var _btnNom = document.getElementById('btnNominaGasto');
  if (_btnNom) _btnNom.textContent = (TRANSLATIONS[lang] || TRANSLATIONS.es)['nom.btn'] || '💼 Nómina';
  var _nd = TRANSLATIONS[lang] || TRANSLATIONS.es;
  var _nEst = document.getElementById('nLblEstado'); if (_nEst) _nEst.textContent = _nd['nom.estado'] || 'Estado';
  var _nPag = document.getElementById('nEstPagado'); if (_nPag) _nPag.textContent = _nd['nom.pagado'] || 'Pagado';
  var _nPen = document.getElementById('nEstPendiente'); if (_nPen) _nPen.textContent = _nd['nom.pendiente'] || 'Pendiente';
  var _nCan = document.getElementById('nBtnCancelar'); if (_nCan) _nCan.textContent = _nd['nom.cancelar'] || 'Cancelar';
  var _nEstLbl = document.getElementById('nLblEstado'); if (_nEstLbl) _nEstLbl.textContent = _nd['nom.estado'] || 'Estado';
  // Actualizar textos del modal nómina
  var _d = TRANSLATIONS[lang] || TRANSLATIONS.es;
  var _nm = {
    'mNominaTit': 'nom.titulo', 'nLblTrabajador': 'nom.trabajador',
    'nLblDni': 'nom.dni', 'nLblPeriodo': 'nom.periodo',
    'nLblFechaPago': 'nom.fecha_pago', 'nLblBruto': 'nom.bruto',
    'nLblIrpf': 'nom.irpf', 'nLblSsTrab': 'nom.ss_trab',
    'nLblSsEmp': 'nom.ss_emp', 'nLblNotas': 'nom.notas',
    'nLblAdjuntar': 'nom.adjuntar', 'nLblRecurrente': 'nom.recurrente',
    'nLblDiaPago': 'nom.dia_pago', 'nLblAvisoRec': 'nom.aviso_rec',
    'nBtnGuardar': 'nom.guardar', 'nLblBrutoRes': 'nom.bruto_lbl',
    'nLblIrpfRes': 'nom.irpf_ret', 'nLblSsTrabRes': 'nom.ss_trab_ret',
    'nLblNeto': 'nom.neto', 'nLblCosteEmp': 'nom.coste_emp'
  };
  Object.keys(_nm).forEach(function(id) {
    var el = document.getElementById(id);
    if (el) el.textContent = _d[_nm[id]] || el.textContent;
  });
  document.documentElement.lang = lang;
  var btn = document.getElementById('btnLangToggle');
  if (btn) btn.textContent = lang.toUpperCase();
  applyLang();
  try { if (typeof renderReps === 'function') renderReps(); } catch(e){}
  try { if (typeof renderDash === 'function') renderDash(); } catch(e){}
  try { if (typeof renderInicioNuevo === 'function') renderInicioNuevo(); } catch(e){}
  try { if (typeof renderPedidosPage === 'function') renderPedidosPage(); } catch(e){}
  try { if (typeof renderGuiaAyuda === 'function') renderGuiaAyuda(); } catch(e){}
  try { if (typeof renderClis === 'function') renderClis(); } catch(e){}
  try { if (typeof renderVentas === 'function') renderVentas(); } catch(e){}
  try { if (typeof renderStock === 'function') renderStock(); } catch(e){}
  try { if (typeof renderCatalogo === 'function' && document.getElementById('pCatalogo') && document.getElementById('pCatalogo').classList.contains('active')) renderCatalogo(); } catch(e){}
  try { if (typeof checkUrgentes === 'function') checkUrgentes(); } catch(e){}
  try { if (typeof actualizarSbControls === 'function') actualizarSbControls(); } catch(e){}
  try { var _pr = document.getElementById('pReportes'); if (typeof renderReporte === 'function' && _pr && _pr.classList.contains('active')) renderReporte(); } catch(e){}
  // Item dinámico de Comisiones (se crea una vez; re-traducir su texto al cambiar idioma)
  try {
    var _ci = document.getElementById('sidebarItemComisiones');
    if (_ci) {
      var _adm = (typeof COMISIONES_MODO !== 'undefined' && COMISIONES_MODO === 'admin');
      _ci.innerHTML = '<span class="sidebar-ni-icon">💼</span>' + (_adm ? T('nav.comisiones') + ' (admin)' : T('nav.mis_comisiones'));
    }
  } catch(e){}
}

// Aplicar idioma a elementos con data-t
function applyLang() {
  document.querySelectorAll('[data-t]').forEach(function(el) {
    var key = el.getAttribute('data-t');
    var attr = el.getAttribute('data-t-attr');
    if (attr) {
      el.setAttribute(attr, T(key));
    } else {
      el.textContent = T(key);
    }
  });
  document.querySelectorAll('[data-t-ph]').forEach(function(el) {
    el.placeholder = T(el.getAttribute('data-t-ph'));
  });
  // data-t-html: para valores que contienen markup (p.ej. <br>). Traducciones de confianza.
  document.querySelectorAll('[data-t-html]').forEach(function(el) {
    el.innerHTML = T(el.getAttribute('data-t-html'));
  });
}

